from __future__ import annotations


def executive_intelligence_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Executive Intelligence Suite</title><style>
:root{color-scheme:dark;--bg:#08111f;--panel:#101b2d;--line:#253750;--text:#eff5ff;--muted:#91a3bd;--accent:#6d8cff;--accent2:#8b5cf6;--ok:#35d08a;--warn:#fbbf24;--bad:#fb7185}*{box-sizing:border-box}body{margin:0;font:14px/1.5 Inter,Segoe UI,Arial,sans-serif;color:var(--text);background:radial-gradient(circle at 80% 0,rgba(109,140,255,.13),transparent 30%),var(--bg)}main{max-width:1450px;margin:auto;padding:28px 28px 90px}.hero{display:grid;grid-template-columns:320px minmax(0,1fr);gap:18px}.card{border:1px solid var(--line);border-radius:18px;background:linear-gradient(145deg,rgba(20,32,54,.96),rgba(11,19,33,.96));box-shadow:0 18px 55px rgba(0,0,0,.24)}.score{padding:27px;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center}.ring{width:180px;height:180px;border-radius:50%;display:grid;place-items:center;background:conic-gradient(var(--accent) calc(var(--score)*1%),rgba(255,255,255,.07) 0);position:relative}.ring:after{content:'';position:absolute;inset:14px;border-radius:50%;background:#0d1829}.ring strong,.ring small{position:relative;z-index:1}.ring strong{font-size:46px}.ring small{display:block;color:var(--muted)}h1{margin:0 0 5px;font-size:27px}h2{font-size:19px;margin:0 0 14px}.muted{color:var(--muted)}.summary{padding:25px}.dimensions{display:grid;grid-template-columns:repeat(4,1fr);gap:11px;margin-top:20px}.dimension{padding:14px;border:1px solid var(--line);border-radius:13px;background:rgba(255,255,255,.025)}.dimension .row{display:flex;justify-content:space-between;gap:8px}.bar{height:7px;background:rgba(255,255,255,.07);border-radius:9px;overflow:hidden;margin-top:10px}.bar span{display:block;height:100%;background:linear-gradient(90deg,var(--accent),var(--accent2))}.grid{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:18px}.section{padding:22px}.risk,.feed,.roi,.dept,.road{padding:13px 0;border-bottom:1px solid rgba(255,255,255,.07)}.risk:last-child,.feed:last-child,.roi:last-child,.dept:last-child,.road:last-child{border-bottom:0}.badge{display:inline-block;padding:3px 7px;border-radius:7px;font-size:10px;text-transform:uppercase;background:rgba(109,140,255,.16);color:#b9c7ff}.badge.critical,.badge.high{background:rgba(251,113,133,.14);color:#fda4af}.badge.medium{background:rgba(251,191,36,.13);color:#fde68a}.title{font-weight:700;margin-top:7px}.detail{color:var(--muted);font-size:12px;margin-top:4px}.dept-line{display:grid;grid-template-columns:minmax(140px,1fr) 70px 45px;gap:12px;align-items:center}.grade{font-weight:800;font-size:17px}.toolbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px;gap:12px}.button{border:1px solid var(--line);border-radius:10px;padding:9px 13px;background:#17253a;color:#fff;cursor:pointer}.button.primary{border:0;background:linear-gradient(135deg,#5578ee,#7b5ce0)}.empty{padding:18px;color:var(--muted);text-align:center}.roadmap{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.roadmap-col{padding:14px;border:1px solid var(--line);border-radius:13px;background:rgba(255,255,255,.02)}@media(max-width:1000px){.hero,.grid{grid-template-columns:1fr}.dimensions{grid-template-columns:repeat(2,1fr)}}@media(max-width:620px){main{padding:18px 13px 80px}.dimensions,.roadmap{grid-template-columns:1fr}.ring{width:150px;height:150px}}
</style></head><body><main><div class="toolbar"><div><h1>Executive Intelligence Suite</h1><div class="muted">Цифровая зрелость, риски, подразделения, ROI и дорожная карта</div></div><button class="button primary" id="refresh">Пересчитать</button></div><div id="app"><div class="empty">Загрузка аналитики…</div></div></main><script>
const esc=v=>String(v??'—').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
function rows(list,render,empty='Данных пока нет'){return list&&list.length?list.map(render).join(''):`<div class="empty">${empty}</div>`}
function render(d){const m=d.digital_maturity||{},dims=Object.values(d.dimensions||{}),roi=d.roi||{},road=d.roadmap||{};document.querySelector('#app').innerHTML=`<section class="hero"><div class="card score"><div class="ring" style="--score:${Number(m.score||0)}"><div><strong>${esc(m.score)}</strong><small>из 100</small></div></div><h2 style="margin-top:18px">Цифровая зрелость</h2><div>${esc(m.level)} · ${esc(m.grade)}</div></div><div class="card summary"><h2>Паспорт цифровой зрелости</h2><div class="muted">Комплексная оценка использования Bitrix24 и управляемости процессов.</div><div class="dimensions">${dims.map(x=>`<div class="dimension"><div class="row"><span>${esc(x.title)}</span><b>${esc(x.score)} · ${esc(x.grade)}</b></div><div class="bar"><span style="width:${Number(x.score||0)}%"></span></div></div>`).join('')}</div></div></section><section class="grid"><div class="card section"><h2>Центр рисков</h2>${rows(d.risks,x=>`<div class="risk"><span class="badge ${esc(x.severity)}">${esc(x.severity)}</span><div class="title">${esc(x.title)}</div><div class="detail">${esc(x.fact)}</div><div class="detail"><b>Последствие:</b> ${esc(x.impact)}</div></div>`,'Критичных рисков не выявлено')}</div><div class="card section"><h2>Executive Feed</h2>${rows(d.executive_feed,x=>`<div class="feed"><span class="badge ${esc(x.severity)}">${esc(x.type)}</span><div class="title">${esc(x.title)}</div><div class="detail">${esc(x.text)}</div></div>`)}</div></section><section class="grid"><div class="card section"><h2>Рейтинг подразделений</h2>${rows((d.department_rating||[]).slice(0,20),x=>`<div class="dept"><div class="dept-line"><div><b>${esc(x.name)}</b><div class="detail">Просрочка: ${esc(x.overdue_rate)}%</div></div><div><div class="bar"><span style="width:${Number(x.score||0)}%"></span></div></div><div class="grade">${esc(x.grade)}</div></div></div>`,'Статистика по подразделениям ещё не накоплена')}</div><div class="card section"><h2>ROI автоматизации</h2><div class="muted">Потенциал: ${esc(roi.total_annual_hours)} часов в год${roi.total_annual_saving_kzt!=null?` · ${Number(roi.total_annual_saving_kzt).toLocaleString('ru-RU')} ₸`:''}</div>${rows((roi.items||[]).slice(0,10),x=>`<div class="roi"><div class="title">${esc(x.title)}</div><div class="detail">До ${esc(x.annual_hours)} часов в год${x.annual_saving_kzt!=null?` · ${Number(x.annual_saving_kzt).toLocaleString('ru-RU')} ₸`:''}</div><div class="detail">${esc(x.recommendation)}</div></div>`,'Кандидаты на автоматизацию не найдены')}</div></section><section class="card section" style="margin-top:18px"><h2>Дорожная карта 30 / 60 / 90 дней</h2><div class="roadmap">${[['30_days','30 дней'],['60_days','60 дней'],['90_days','90 дней']].map(([k,t])=>`<div class="roadmap-col"><b>${t}</b>${rows(road[k],x=>`<div class="road"><div class="title">${esc(x.title)}</div><div class="detail">${esc(x.action)}</div></div>`)}</div>`).join('')}</div></section>`}
async function load(rebuild=false){document.querySelector('#app').innerHTML='<div class="empty">Пересчитываю показатели…</div>';let r=await fetch(rebuild?'/executive-intelligence/collect':'/executive-intelligence/latest',{method:rebuild?'POST':'GET',cache:'no-store'});if(!r.ok&& !rebuild)r=await fetch('/executive-intelligence/collect',{method:'POST'});if(!r.ok){document.querySelector('#app').innerHTML='<div class="empty">Не удалось получить данные</div>';return}render(await r.json())}document.querySelector('#refresh').onclick=()=>load(true);load();
</script></body></html>'''
